// Simulate a batch of transactions from an external bank feed.
// Replace this with a real data source: Google Sheets, Kafka, webhook, DB query, etc.
const patterns = [
  // Fan-out: one source, many recipients
  { 'From Bank':'1','From Account':'A_LAUNDER_01','To Bank':'2','To Account':'A_REC_01','Amount Paid':25000,'Payment Format':'Wire' },
  { 'From Bank':'1','From Account':'A_LAUNDER_01','To Bank':'3','To Account':'A_REC_02','Amount Paid':24500,'Payment Format':'Wire' },
  { 'From Bank':'1','From Account':'A_LAUNDER_01','To Bank':'4','To Account':'A_REC_03','Amount Paid':25500,'Payment Format':'Wire' },
  // Stack: chain A → B → C
  { 'From Bank':'5','From Account':'B_CHAIN_01','To Bank':'6','To Account':'B_CHAIN_02','Amount Paid':18000,'Payment Format':'SWIFT' },
  { 'From Bank':'6','From Account':'B_CHAIN_02','To Bank':'7','To Account':'B_CHAIN_03','Amount Paid':17800,'Payment Format':'SWIFT' },
  { 'From Bank':'7','From Account':'B_CHAIN_03','To Bank':'8','To Account':'B_CHAIN_04','Amount Paid':17600,'Payment Format':'SWIFT' },
];
// Randomise amounts slightly so each run looks different
return patterns.map(tx => ({
  json: {
    ...tx,
    'Amount Paid': Math.round(tx['Amount Paid'] * (0.95 + Math.random() * 0.1)),
    Timestamp: new Date().toISOString().replace('T',' ').slice(0,16),
  }
}));

const resp = $input.first().json;
const body = typeof resp.body === 'string' ? JSON.parse(resp.body) : resp.body;
console.log(`Argus ingestion: stored=${body.stored}, rejected=${body.rejected?.length ?? 0}, queued=${body.total_queued}`);
return [{ json: body }];
